// T619 NodeTypeRegistrar — SETNX + atomic dual-write + lock release in catch
const NODE_TYPE_LOCK_PREFIX = 'node-type-reg-lock' as const;

async registerNodeType(nodeTypeId: string, schema: Record<string, unknown>): Promise<DataProcessResult<Record<string, unknown>>> {
  const tenantId = this.tenantContext.getTenantId();
  const lockKey = `${NODE_TYPE_LOCK_PREFIX}:${nodeTypeId}`;

  // ORDER 1: SETNX — prevent duplicate registration
  const lockResult = await this.db.searchDocuments('node-type-locks', { lockKey });
  if (lockResult.data?.length) {
    return DataProcessResult.success({ nodeTypeId, alreadyRegistered: true });
  }
  await this.db.storeDocument('node-type-locks', { lockKey, nodeTypeId, createdAt: new Date().toISOString() });

  try {
    // ORDER 2: storeDocument nodeType (GLOBAL scope)
    await this.db.storeDocument('node-types', { nodeTypeId, tenantId, schema, scope: 'GLOBAL', registeredAt: new Date().toISOString() });

    // ORDER 3: storeDocument capabilityIndex
    await this.db.storeDocument('capability-index', { nodeTypeId, tenantId, capabilities: schema['capabilities'] ?? [], indexedAt: new Date().toISOString() });

    // DNA-8: audit BEFORE enqueue
    await this.db.storeDocument('node-type-audit', { nodeTypeId, tenantId, action: 'REGISTERED', registeredAt: new Date().toISOString() });
    await this.queue.enqueue('NodeTypeRegistered', { nodeTypeId, tenantId, registeredAt: new Date().toISOString() });
    return DataProcessResult.success({ nodeTypeId, tenantId });
  } catch (err) {
    // MUST release lock on failure — .catch(() => {}) prevents secondary error
    await this.db.deleteDocument('node-type-locks', lockKey).catch(() => {});
    return DataProcessResult.failure('REGISTRATION_FAILED', String(err));
  }
}
